/**
 * Main App Component
 * Root component for World Builder
 */

import React, { useEffect, useState } from 'react';
import useWorldBuilderStore from './store/store.js';
import AreaBrowser from './components/AreaBrowser.jsx';
import RoomGrid from './components/RoomGrid.jsx';
import EntityBrowser from './components/EntityBrowser.jsx';
import PropertyPanel from './components/PropertyPanel.jsx';
import Notifications from './components/Notifications.jsx';
import './App.css';

function App() {
  const [activeView, setActiveView] = useState('rooms');
  const { loadAreas } = useWorldBuilderStore();

  useEffect(() => {
    // Load areas on startup
    loadAreas();
  }, [loadAreas]);

  return (
    <div className="app">
      <header className="app-header">
        <h1>🗺️ ROM World Builder</h1>
        <p>Graphical Area & Room Editor for ROM 2.4</p>
      </header>

      <div className="app-container">
        <aside className="sidebar">
          <AreaBrowser />
        </aside>

        <main className="main-content">
          <div className="view-tabs">
            <button
              className={`view-tab ${activeView === 'rooms' ? 'active' : ''}`}
              onClick={() => setActiveView('rooms')}
            >
              Rooms
            </button>
            <button
              className={`view-tab ${activeView === 'entities' ? 'active' : ''}`}
              onClick={() => setActiveView('entities')}
            >
              Mobiles/Objects/Resets
            </button>
          </div>
          {activeView === 'rooms' ? <RoomGrid /> : <EntityBrowser />}
        </main>

        <aside className="sidebar right-sidebar">
          <PropertyPanel />
        </aside>
      </div>

      <Notifications />
    </div>
  );
}

export default App;
